Certainly! Below is a simple example of a Visual Studio Code extension with two files, `extension.ts` and `package.json`. This extension adds a command that opens a webview within VS Code that displays the "cppreference" website.

Here's the `extension.ts` file:

```typescript
import * as vscode from 'vscode';

export function activate(context: vscode.ExtensionContext) {
    let disposable = vscode.commands.registerCommand('extension.openCppReference', () => {
        // Create and show a new webview
        const panel = vscode.window.createWebviewPanel(
            'cppReference', // Identifies the type of the webview. Used internally
            'CppReference', // Title of the webview panel displayed to the user
            vscode.ViewColumn.One, // Editor column to show the new webview panel in.
            {} // Webview options. We're not setting any for this example.
        );

        // And set its HTML content
        panel.webview.html = getWebviewContent();
    });

    context.subscriptions.push(disposable);
}

export function deactivate() {}

function getWebviewContent() {
    return `<!DOCTYPE html>
        <html lang="en">
        <head>
            <meta charset="UTF-8">
            <meta http-equiv="Content-Security-Policy" content="default-src 'none'; frame-src https://en.cppreference.com/; style-src 'unsafe-inline';">
            <meta name="viewport" content="width=device-width, initial-scale=1.0">
            <title>CppReference</title>
        </head>
        <body>
            <iframe src="https://en.cppreference.com/w/" frameborder="0" style="width:100%; height:100vh;"></iframe>
        </body>
        </html>`;
}
```

